-- Repartidor de misiones
lang["#MISSION_GIVER_PHILLIPS"] = "Capitán Ranger Phillips"
lang["#MISSION_GIVER_PHILLIPS_SUBTITLE"] = "Rangers del Desierto"
lang["#MISSION_GIVER_PHILLIPS_NEW"] = "Bueno, cómo está, no esperaba que nadie apareciera por este lugar. ¿Buscas echarnos una mano?"
lang["#MISSION_GIVER_PHILLIPS_GREET_NO"] = "Te has metido con demasiados de los nuestros. Debería hacerte pagar por lo que has hecho."
lang["#MISSION_GIVER_PHILLIPS_GREET_0"] = "Adelante, prepárate para ensuciarte las manos. Tenemos mucho que limpiar por aquí."
lang["#MISSION_GIVER_PHILLIPS_GREET_25"] = "Tengo un montón de cosas que algunos de los rangers de aquí no quieren hacer. Hay que empezar por algún lado, ¿verdad? Aquí tienes."
lang["#MISSION_GIVER_PHILLIPS_GREET_150"] = "Estás haciendo un buen trabajo aquí. Sigue con el esfuerzo, hijo."
lang["#MISSION_GIVER_PHILLIPS_GREET_300"] = "Casi puedo llamarte uno de los nuestros. La gente como tú abunda por aquí."
lang["#MISSION_GIVER_PHILLIPS_GREET_400"] = "$playername, ¡estás pateando culos ahí fuera!"
lang["#MISSION_GIVER_PHILLIPS_GREET_750"] = "¡Sigue así y tal vez tengamos que escribir tu nombre en algún sitio!"
lang["#MISSION_GIVER_PHILLIPS_GREET_999"] = "$playername, has sido bueno con nosotros. Ahora te lo devolveré. Ven a hablar conmigo cuando tengas tiempo."

-- Misiones únicas
lang["#MISSION_PHILLIPS_PATROL"] = "Patrulla de Alimañas"
lang["#MISSION_PHILLIPS_PATROL_DESC"] = "Empecemos con algo simple. A ver si puedes hacer cosas. Los geckos nos han estado molestando por aquí, ¿crees que podrías reducir un poco la manada por mí?"
lang["#MISSION_PHILLIPS_PATROL_HINT"] = "Mata a 10 geckos en Yolla Bolly."
lang["#MISSION_PHILLIPS_PATROL_COMPLETE"] = "Bueno, ¿quién lo diría? Puede que seas de alguna utilidad para nosotros. Déjame ver qué más puedo conseguirte."

lang["#MISSION_PHILLIPS_TECHNICAL"] = "Dificultades Técnicas"
lang["#MISSION_PHILLIPS_TECHNICAL_DESC"] = "Es difícil no ver la torre de radio gigante fuera, ¿verdad? Hemos estado tratando de ponerla en marcha durante las últimas semanas, pero le faltan muchas piezas. Tenemos noticias de que hay algunas placas de circuito viejas en el antiguo búnker gubernamental cercano. Están en perfecto estado. Tienen un inconveniente, están intactas porque están en uno de esos silos radiactivos. Si pudieras conseguirnos eso, sería de gran ayuda para que esa cosa funcione. Puedo darte algo de Rad-Away después también. Buena suerte y no brilles demasiado en el camino de vuelta."
lang["#MISSION_PHILLIPS_TECHNICAL_HINT"] = "Encuentra la Placa de Circuito en el Silo del Búnker de Yolla Bolly."
lang["#MISSION_PHILLIPS_TECHNICAL_COMPLETE"] = "Bueno, definitivamente tienes un poco de resplandor, pero nada que un Rad-Away no pueda arreglar. Bien hecho, ese es un paso más para volver a contactar con nuestros chicos en casa."
lang["#MISSION_PHILLIPS_TECHNICAL_ITEMNAME"] = "Placa de Circuito Prístina"

lang["#MISSION_PHILLIPS_STRANGEMAT"] = "Materiales Extraños"
lang["#MISSION_PHILLIPS_STRANGEMAT_DESC"] = "¿Has visto a esos extraños tipos fuertemente blindados que han estado aterrizando para destrozar todo? Resulta que incluso después de destrozar su armadura solo para matarlos, algunas de las placas que llevan aún valen la pena. Queremos ver qué podemos hacer con ellas para mejorar nuestra armadura. Confío en ti para esta. No será fácil, pero puedo darte algo de nuestro equipo para compensarlo."
lang["#MISSION_PHILLIPS_STRANGEMAT_HINT"] = "Localiza un Material Avanzado para los Rangers del Desierto."
lang["#MISSION_PHILLIPS_STRANGEMAT_COMPLETE"] = "Bueno, demonios, $playername. Vamos a tener que ver qué podemos hacer con esto."

lang["#MISSION_PHILLIPS_AHEAD"] = "El Camino por Delante"
lang["#MISSION_PHILLIPS_AHEAD_DESC"] = "Gracias a ti nos va bastante bien por aquí. Les he dicho a algunos de los rangers que empiecen a buscar qué hay al norte. Nuestro progreso se ha visto frenado por esos malditos francotiradores caníbales en el Paso de Montaña. ¿Crees que podrías reducir su número para que podamos pasar?"
lang["#MISSION_PHILLIPS_AHEAD_HINT"] = "Elimina a los Bandidos Pico de Hielo para que los Rangers puedan continuar su expedición."
lang["#MISSION_PHILLIPS_AHEAD_COMPLETE"] = "Por fin podemos empezar a buscar el norte gracias a ti. Buen trabajo."

lang["#MISSION_PHILLIPS_RESPECTS"] = "Pagando Respetos"
lang["#MISSION_PHILLIPS_RESPECTS_DESC"] = "Tengo algo que realmente necesito que hagas. Uno de los nuestros no regresó mientras luchaba contra algunos mutantes en el Búnker de las Tierras de Ceniza. Llevaba consigo el osito de peluche de su hija para llevarlo a aventuras por ella. Necesito que encuentres esa cosa y la devuelvas para ella. Por favor. Sé que pido mucho solo por un osito de peluche, pero significaría mucho para todos nosotros."
lang["#MISSION_PHILLIPS_RESPECTS_ITEMNAME"] = "Osito de Peluche del Ranger Caído"
lang["#MISSION_PHILLIPS_RESPECTS_HINT"] = "Encuentra el osito de peluche del ranger caído para su hija."
lang["#MISSION_PHILLIPS_RESPECTS_COMPLETE"] = "Gracias por arriesgar tu vida por esto. Me aseguraré de que llegue a ella pronto después de limpiarlo un poco."

lang["#MISSION_PHILLIPS_RANGER"] = "El Camino del Ranger"
lang["#MISSION_PHILLIPS_RANGER_DESC"] = "Después de todo lo que has hecho, es hora de convertirte en uno de los nuestros. Necesito que reúnas un montón de suministros para poder hacerte una armadura adecuada. Algunos pueden parecerte extraños, pero es un rito de iniciación que todos tuvimos que completar. Buena suerte."
lang["#MISSION_PHILLIPS_RANGER_HINT"] = "Recoge los elementos necesarios para completar el Camino del Ranger."
lang["#MISSION_PHILLIPS_RANGER_COMPLETE"] = "Por fin eres uno de los nuestros. No vayas a vender esto a cualquier yermo. Tienen que ganarse sus galones como tú. Felicidades, Ranger $playername. Mantén el yermo a salvo de cualquier amenaza y trata a la gente amable con respeto. Haz de este un lugar mejor para vivir sin miedo a daños o sufrimientos."

lang["#MISSION_PHILLIPS_DEATHCLAW"] = "Cuanto más grandes son..."
lang["#MISSION_PHILLIPS_DEATHCLAW_DESC"] = "Ahora que eres un Ranger del Desierto, es hora de que te revele un pequeño secreto. Tenemos un arma que se ha transmitido de generación en generación de rangers, y si puedes demostrar que tienes habilidad incluso con su contraparte menor, entonces te otorgaremos esta arma. La elección del cazador, el Revólver de Caza es un arma de fuego de alto calibre y alta clase. Patea como un burro y golpea como un brahmán. Esta cosa puede derribar desde un simple bandido hasta un poderoso Sanguinario. Y lo vas a demostrar cazando y matando a los Sanguinarios que plagan estas montañas. Diezma las manadas de estos bastardos y luego infórmame para la segunda parte de la prueba."
lang["#MISSION_PHILLIPS_DEATHCLAW_HINT"] = "Mata a 40 Sanguinarios con un Revólver de Caza en la Cordillera de Yolla Bolly."
lang["#MISSION_PHILLIPS_DEATHCLAW_COMPLETE"] = "Eso es un maldito buen trabajo, $playername. Maldito buen trabajo el que hiciste. Ahora que conoces el arma y cómo manejarla, es hora de poner tus habilidades a prueba. Vamos a eliminar la fuente de estas malditas abominaciones."

lang["#MISSION_PHILLIPS_SEQUIOA"] = "...Más Duro Caerán"
lang["#MISSION_PHILLIPS_SEQUIOA_DESC"] = "Como dije anteriormente, has demostrado que tienes talento. Pero necesito que pongas esas habilidades a prueba. Necesitamos que elimines a las Matriarcas que están engendrando estos horrores del yermo. Mátalas donde sea, no importa. Solo asegúrate de usar el Revólver de Caza cuando las derribes."
lang["#MISSION_PHILLIPS_SEQUIOA_HINT"] = "Mata a 10 Matriarcas Sanguinarias con un Revólver de Caza."
lang["#MISSION_PHILLIPS_SEQUIOA_COMPLETE"] = "Excelente trabajo, ranger. Con sus números reducidos y la amenaza neutralizada, debería pasar bastante tiempo antes de que vuelvan a amenazarnos. Y con esto has completado todo lo que se te ha pedido. Te entrego esta arma con orgullo y honor. Trata bien a la Secuoya y te salvará la vida."

lang["#MISSION_PHILLIPS_FRONTIER"] = "En la Frontera"
lang["#MISSION_PHILLIPS_FRONTIER_DESC"] = "Ahora que tienes el arma verdadera de un Ranger del Desierto, estoy seguro de que estás ansioso por probarla. La suerte está de tu lado, tengo el objetivo perfecto. Los rumores de un Sanguinario de estatura mítica han sido confirmados por algunos exploradores recientemente. Unguem Mortis. Signifique lo que signifique, es mortal. Ya ha matado a algunos Rangers, así que considéralo mortal. Recomiendo reunir un equipo antes de enfrentarte a él. Los Rangers que fueron solos ya están a dos metros bajo tierra. Acaba con esa abominación con un poco de justicia de la frontera."
lang["#MISSION_PHILLIPS_FRONTIER_HINT"] = "Mata a Unguem Mortis con la Secuoya del Ranger. Puede aparecer raramente en la región de las Tierras de Ceniza."
lang["#MISSION_PHILLIPS_FRONTIER_COMPLETE"] = "Bueno, que me aspen. Te las arreglaste para acabar con esa bestia con tu viejo revólver. Todo un logro. Aquí está tu recompensa, Ranger."

lang["#MISSION_PHILLIPS_PEACEMAKER"] = "Pacificador"
lang["#MISSION_PHILLIPS_PEACEMAKER_DESC"] = "Ranger, hay algo que tengo que decirte. Estoy orgulloso de ti. Te ha ido bien desde que te uniste a los Rangers del Desierto. Recuerdo que te uniste como un escuálido saqueador, y pensé que te unirías a los muertos en las profundidades en poco tiempo. Sin embargo, considera que mi posición ha cambiado... Has crecido en tu papel y te has ganado con creces tu lugar. Es mi placer personal anunciar que el cuartel general ha aprobado una mejora para tu armadura. Bien hecho, $playername."
lang["#MISSION_PHILLIPS_PEACEMAKER_HINT"] = "Recoge los elementos necesarios para completar la misión Pacificador."
lang["#MISSION_PHILLIPS_PEACEMAKER_COMPLETE"] = "¡Felicitaciones! Has derramado sangre, roca y balas como solo unos pocos antes que tú. Has viajado lejos y ancho, has luchado y perseverado, y ahora te has ganado tu estatus de Veterano. Si buscas más trabajo, siempre hay alguien que te necesita."

-- Misiones repetibles, dadas después de completar "Patrulla de Alimañas" y "Dificultades Técnicas"
lang["#MISSION_PHILLIPS_PUTTING"] = "Juntándolo Todo"
lang["#MISSION_PHILLIPS_PUTTING_DESC"] = "Ahora podemos empezar a arreglar las partes estructurales de esta torre. Va a necesitar cualquier trozo de metal que tengas y un kit de soldadura."
lang["#MISSION_PHILLIPS_PUTTING_HINT"] = "Localiza Metal de Desecho y un kit de soldadura para ayudar a los rangers a reparar su torre."
lang["#MISSION_PHILLIPS_PUTTING_COMPLETE"] = "Esto no servirá para una reparación completa, pero es un buen comienzo. Gracias."
    
lang["#MISSION_PHILLIPS_LURKING"] = "Acechando Mortalmente"
lang["#MISSION_PHILLIPS_LURKING_DESC"] = "Podría usar ayuda para limpiar a algunos de esos malditos Mirelurks que están enraizando en el valle debajo de los Supervivientes. Han sido un dolor en el culo cuando necesitamos ir allí por suministros."
lang["#MISSION_PHILLIPS_LURKING_HINT"] = "Mata a 10 Mirelurks en Yolla Bolly cerca del Pueblo de Supervivientes."
lang["#MISSION_PHILLIPS_LURKING_COMPLETE"] = "Estoy seguro de que habrá más, pero esto hará que los próximos viajes sean un poco más seguros. Gracias, amigo."

lang["#MISSION_PHILLIPS_CRUSHER"] = "Trituradora de Rocas"
lang["#MISSION_PHILLIPS_CRUSHER_DESC"] = "Podríamos usar ayuda para limpiar a esos malditos vagabundos que viven en las minas. El valle podría dormir mucho más seguro sin que secuestren y asesinen gente."
lang["#MISSION_PHILLIPS_CRUSHER_HINT"] = "Elimina a los Muerde Rocas en las minas de Yolla Bolly."
lang["#MISSION_PHILLIPS_CRUSHER_COMPLETE"] = "Podríamos dormir bien esta noche sin tener que preocuparnos de que vengan a tocar a nuestra puerta."

lang["#MISSION_PHILLIPS_FOODPREP"] = "Preparación de Comida"
lang["#MISSION_PHILLIPS_FOODPREP_DESC"] = "He estado buscando una manera de mantener la moral alta para el resto del equipo. Ellos son los que están rodando en el barro y luchando contra los malos. Una de nuestras comidas favoritas es el Wellington de Sanguinario. Sé lo que estás pensando. Pero no te preocupes, ¡haré que valga la pena!"
lang["#MISSION_PHILLIPS_FOODPREP_HINT"] = "Localiza huevos y carne de Sanguinario."
lang["#MISSION_PHILLIPS_FOODPREP_COMPLETE"] = "Santo cielo, realmente lo hiciste. Los chicos te llevarán en sus corazones cuando lleguen a cenar. Gran trabajo, $playername."

-- Misiones repetibles, dadas después de completar "El Camino del Ranger"
lang["#MISSION_PHILLIPS_DRUG_SEIZURE"] = "Incautación de Drogas"
lang["#MISSION_PHILLIPS_DRUG_SEIZURE_DESC"] = "Hiciste un buen trabajo limpiando las carreteras del norte, pero esos traficantes de drogas en el Paso de Montaña han estado aprovechándose para enviar su inmundicia al sur. Necesito que interrumpas sus planes y les hagas saber que no son bienvenidos en el sur."
lang["#MISSION_PHILLIPS_DRUG_SEIZURE_HINT"] = "Mata a 10 Agentes de Cipher en la región del Paso de Montaña."
lang["#MISSION_PHILLIPS_DRUG_SEIZURE_COMPLETE"] = "Con suerte, eso les mostrará lo que pasa cuando intentan expandir sus 'operaciones' hacia nuestro hogar."

lang["#MISSION_PHILLIPS_UNION_BUSTING"] = "Rompiendo la Unión"
lang["#MISSION_PHILLIPS_UNION_BUSTING_DESC"] = "Esos bastardos Muerde Rocas han estado golpeando duro a los Supervivientes del Valle, recolectando esclavos para el comercio y sus minas. No nos quedaremos de brazos cruzados y dejaremos que esto suceda."
lang["#MISSION_PHILLIPS_UNION_BUSTING_HINT"] = "Mata a 1 Merodeador Muerde Rocas, 2 Rompevetas Muerde Rocas y 10 Capataces Muerde Rocas."
lang["#MISSION_PHILLIPS_UNION_BUSTING_COMPLETE"] = "Buena mierda, $playername. Todos en el valle respirarán un poco más tranquilos sabiendo que esos bastardos duermen a dos metros bajo tierra."

RELOADSCHEMA = true